ENCODER_PATH = MODEL_DIR / "label_encoder.pkl"
ENCODINGS_PATH = MODEL_DIR / "face_encodings.pkl"

# Create directories
MODEL_DIR.mkdir(exist_ok=True)
TRAINING_DATA_DIR.mkdir(exist_ok=True)

app = FastAPI(
    title="Office Facial Recognition Security System",
    description="API for employee facial recognition with confidence scoring",
    version="1.0.0"
)


class FaceRecognitionModel:
    """Manages the facial recognition model lifecycle."""

    def __init__(self):
        self.model: Optional[CalibratedClassifierCV] = None
        self.label_encoder: Optional[LabelEncoder] = None
        self.known_encodings: list = []
        self.known_labels: list = []
        self.is_trained: bool = False
        self._load_model()

    def _load_model(self):
        """Load existing model from disk if available."""
        try:
            if MODEL_PATH.exists() and ENCODER_PATH.exists() and ENCODINGS_PATH.exists():
                with open(MODEL_PATH, "rb") as f:
                    self.model = pickle.load(f)
                with open(ENCODER_PATH, "rb") as f:
                    self.label_encoder = pickle.load(f)
                with open(ENCODINGS_PATH, "rb") as f:
                    data = pickle.load(f)
                    self.known_encodings = data["encodings"]
                    self.known_labels = data["labels"]
                self.is_trained = True
                logger.info(f"Model loaded. Known employees: {list(self.label_encoder.classes_)}")
        except Exception as e:
            logger.error(f"Error loading model: {e}")
            self.is_trained = False

    def _save_model(self):
        """Persist model to disk."""
        with open(MODEL_PATH, "wb") as f:
            pickle.dump(self.model, f)
        with open(ENCODER_PATH, "wb") as f:
            pickle.dump(self.label_encoder, f)
        with open(ENCODINGS_PATH, "wb") as f:
            pickle.dump({
                "encodings": self.known_encodings,
                "labels": self.known_labels
            }, f)
        logger.info("Model saved to disk.")

    def add_employee_photos(self, employee_id: str, image_paths: list[str]) -> dict:
        """Extract face encodings from employee photos and add to training data."""
        employee_dir = TRAINING_DATA_DIR / employee_id
        employee_dir.mkdir(exist_ok=True)

        encodings_added = 0
        errors = []

        for img_path in image_paths:
            try:
                image = face_recognition.load_image_file(img_path)
                face_locations = face_recognition.face_locations(image, model="hog")

                if len(face_locations) == 0:
                    errors.append(f"No face detected in {Path(img_path).name}")
                    continue
                elif len(face_locations) > 1:
                    errors.append(f"Multiple faces detected in {Path(img_path).name}, using largest face")
                    # Use the largest face (by area)
                    face_locations = [max(face_locations, key=lambda loc: (loc[2] - loc[0]) * (loc[1] - loc[3]))]

                face_encs = face_recognition.face_encodings(image, face_locations)

                if face_encs:
                    self.known_encodings.append(face_encs[0])
                    self.known_labels.append(employee_id)
                    encodings_added += 1

                    # Save a copy of the photo
                    dest = employee_dir / Path(img_path).name
                    if Path(img_path) != dest:
                        shutil.copy2(img_path, dest)

            except Exception as e:
                errors.append(f"Error processing {Path(img_path).name}: {str(e)}")

        return {
            "employee_id": employee_id,
            "encodings_added": encodings_added,
            "total_encodings": sum(1 for l in self.known_labels if l == employee_id),
            "errors": errors
        }

    def train(self) -> dict:
        """Train the SVM classifier with calibrated probabilities."""
        if len(self.known_encodings) == 0:
            raise ValueError("No training data available. Add employee photos first.")

        unique_labels = set(self.known_labels)
        if len(unique_labels) < 2:
            raise ValueError(f"Need at least 2 employees to train. Currently have {len(unique_labels)}.")

        # Check minimum samples per class
        label_counts = {}
        for label in self.known_labels:
            label_counts[label] = label_counts.get(label, 0) + 1

        for label, count in label_counts.items():
            if count < 2:
                raise ValueError(
                    f"Employee '{label}' has only {count} photo(s). Need at least 2 per employee."
                )

        X = np.array(self.known_encodings)
        self.label_encoder = LabelEncoder()
        y = self.label_encoder.fit_transform(self.known_labels)

        # Use SVM with probability calibration for reliable confidence scores
        base_svm = SVC(kernel="rbf", gamma="scale", C=10.0)
        # Use min of 3 or minimum class count for CV folds
        min_samples = min(label_counts.values())
        cv_folds = min(3, min_samples)
        self.model = CalibratedClassifierCV(base_svm, cv=cv_folds, method="sigmoid")
        self.model.fit(X, y)

        self.is_trained = True
        self._save_model()

        logger.info(f"Model trained with {len(unique_labels)} employees and {len(X)} total samples.")

        return {
            "status": "trained",
            "num_employees": len(unique_labels),
            "employees": {emp: label_counts[emp] for emp in sorted(unique_labels)},
            "total_samples": len(X)
        }

    def recognize(self, image_path: str, threshold: float = 0.5) -> dict:
        """
        Recognize faces in an image and return detailed probability distributions.
        """
        if not self.is_trained:
            raise ValueError("Model is not trained yet. Train the model first.")

        image = face_recognition.load_image_file(image_path)
        face_locations = face_recognition.face_locations(image, model="hog")

        if len(face_locations) == 0:
            return {
                "faces_detected": 0,
                "results": [],
                "timestamp": datetime.utcnow().isoformat(),
                "message": "No faces detected in the image."
            }

        face_encodings = face_recognition.face_encodings(image, face_locations)
        results = []

        for i, (face_enc, face_loc) in enumerate(zip(face_encodings, face_locations)):
            top, right, bottom, left = face_loc

            # Get probability distribution from calibrated SVM
            probabilities = self.model.predict_proba([face_enc])[0]
            class_names = self.label_encoder.classes_

            # Build probability distribution
            probability_distribution = {}
            for name, prob in zip(class_names, probabilities):
                probability_distribution[name] = round(float(prob), 6)

            # Sort by probability descending
            probability_distribution = dict(
                sorted(probability_distribution.items(), key=lambda x: x[1], reverse=True)
            )

            # Best match
            best_idx = np.argmax(probabilities)
            best_match = class_names[best_idx]
            best_confidence = float(probabilities[best_idx])

            # Compute face distance to all known encodings for additional context
            face_distances = face_recognition.face_distance(
                np.array(self.known_encodings), face_enc
            )

            # Per-employee average distances
            employee_distances = {}
            for label, dist in zip(self.known_labels, face_distances):
                if label not in employee_distances:
                    employee_distances[label] = []
                employee_distances[label].append(float(dist))

            avg_distances = {
                emp: round(np.mean(dists), 6)
                for emp, dists in sorted(employee_distances.items(), key=lambda x: np.mean(x[1]))
            }
            min_distances = {
                emp: round(np.min(dists), 6)
                for emp, dists in sorted(employee_distances.items(), key=lambda x: np.min(x[1]))
            }

            # Determine if the face is recognized or unknown
            is_recognized = best_confidence >= threshold

            result = {
                "face_index": i,
                "bounding_box": {
                    "top": top,
                    "right": right,
                    "bottom": bottom,
                    "left": left
                },
                "recognized": is_recognized,
                "best_match": {
                    "employee_id": best_match if is_recognized else "UNKNOWN",
                    "confidence": round(best_confidence, 6),
                    "above_threshold": is_recognized
                },
                "probability_distribution": probability_distribution,
                "face_distances": {
                    "average_per_employee": avg_distances,
                    "minimum_per_employee": min_distances
                },
                "recognition_threshold": threshold,
                "entropy": round(float(-np.sum(probabilities * np.log2(probabilities + 1e-10))), 6)
            }

            results.append(result)

        return {
            "faces_detected": len(face_locations),
            "results": results,
            "timestamp": datetime.utcnow().isoformat(),
            "model_info": {
                "num_employees": len(self.label_encoder.classes_),
                "employees": list(self.label_encoder.classes_),
                "total_training_samples": len(self.known_encodings)
            }
        }


# Initialize the model
face_model = FaceRecognitionModel()


