@app.get("/employees")
async def list_employees():
    """List all registered employees and their photo counts."""
    if not face_model.known_labels:
        return {"employees": [], "total": 0}

    label_counts = {}
    for label in face_model.known_labels:
        label_counts[label] = label_counts.get(label, 0) + 1

    employees = [
        {"employee_id": emp, "num_photos": count}
        for emp, count in sorted(label_counts.items())
    ]

    return {
        "employees": employees,
        "total": len(employees),
        "model_trained": face_model.is_trained
    }


@app.post("/employees/{employee_id}/photos")
async def upload_employee_photos(employee_id: str, files: list[UploadFile] = File(...)):
    """Upload one or more photos for an employee."""
    if not files:
        raise HTTPException(status_code=400, detail="No files uploaded.")

    temp_paths = []
    try:
        for file in files:
            if not file.content_type or not file.content_type.startswith("image/"):
                raise HTTPException(
                    status_code=400,
                    detail=f"File {file.filename} is not an image. Content type: {file.content_type}"
                )

            suffix = Path(file.filename).suffix if file.filename else ".jpg"
            with tempfile.NamedTemporaryFile(delete=False, suffix=suffix) as tmp:
                content = await file.read()
                tmp.write(content)
                temp_paths.append(tmp.name)

        result = face_model.add_employee_photos(employee_id, temp_paths)

        if result["encodings_added"] == 0:
            raise HTTPException(
                status_code=400,
                detail={
                    "message": "No valid face encodings could be extracted from the uploaded photos.",
                    "errors": result["errors"]
                }
            )

        return {
            "status": "success",
            "data": result,
            "message": f"Added {result['encodings_added']} face encoding(s) for employee '{employee_id}'.",
            "note": "Remember to retrain the model after adding new photos."
        }

    finally:
        for path in temp_paths:
            try:
                os.unlink(path)
            except OSError:
                pass


@app.delete("/employees/{employee_id}")
async def remove_employee(employee_id: str):
    """Remove an employee from the training data."""
    indices_to_remove = [
        i for i, label in enumerate(face_model.known_labels) if label == employee_id
    ]

    if not indices_to_remove:
        raise HTTPException(status_code=404, detail=f"Employee '{employee_id}' not found.")

    # Remove in reverse order to maintain correct indices
    for idx in sorted(indices_to_remove, reverse=True):
        face_model.known_encodings.pop(idx)
        face_model.known_labels.pop(idx)

    # Remove training data directory
    employee_dir = TRAINING_DATA_DIR / employee_id
    if employee_dir.exists():
        shutil.rmtree(employee_dir)

    # Mark model as needing retraining
    face_model.is_trained = False

    return {
        "status": "success",
        "message": f"Removed employee '{employee_id}' ({len(indices_to_remove)} encodings removed).",
        "note": "Model needs to be retrained."
    }


