@app.post("/recognize")
async def recognize_face(
    file: UploadFile = File(...),
    threshold: float = 0.5
):
    """
    Recognize faces in an uploaded image.
    
    Returns detailed probability distribution over all known employees
    for each detected face, along with face distances and confidence metrics.
    
    - **file**: Image file containing one or more faces
    - **threshold**: Minimum confidence to consider a face as recognized (0.0 to 1.0)
    """
    if not face_model.is_trained:
        raise HTTPException(
            status_code=400,
            detail="Model is not trained. Upload employee photos and train the model first."
        )

    if threshold < 0.0 or threshold > 1.0:
        raise HTTPException(status_code=400, detail="Threshold must be between 0.0 and 1.0.")

    if not file.content_type or not file.content_type.startswith("image/"):
        raise HTTPException(status_code=400, detail=f"Uploaded file is not an image.")

    try:
        suffix = Path(file.filename).suffix if file.filename else ".jpg"
        with tempfile.NamedTemporaryFile(delete=False, suffix=suffix) as tmp:
            content = await file.read()
            tmp.write(content)
            tmp_path = tmp.name

        result = face_model.recognize(tmp_path, threshold=threshold)

        # Add security assessment
        for face_result in result.get("results", []):
            confidence = face_result["best_match"]["confidence"]
            entropy = face_result["entropy"]

            if face_result["recognized"]:
                if confidence > 0.85:
                    security_level = "HIGH_CONFIDENCE"
                elif confidence > 0.7:
                    security_level = "MEDIUM_CONFIDENCE"
                else:
                    security_level = "LOW_CONFIDENCE"
            else:
                security_level = "UNRECOGNIZED"

            face_result["security_assessment"] = {
                "level": security_level,
                "recommendation": _get_security_recommendation(security_level),
                "uncertainty": "LOW" if entropy < 1.0 else "MEDIUM" if entropy < 2.0 else "HIGH"
            }

        return JSONResponse(content=result)

    except ValueError as e:
        raise HTTPException(status_code=400, detail=str(e))
    except Exception as e:
        logger.error(f"Recognition error: {e}")
        raise HTTPException(status_code=500, detail=f"Recognition failed: {str(e)}")
    finally:
        try:
            os.unlink(tmp_path)
        except (OSError, UnboundLocalError):
            pass


def _get_security_recommendation(level: str) -> str:
    recommendations = {
        "HIGH_CONFIDENCE": "Access granted. Identity verified with high confidence.",
        "MEDIUM_CONFIDENCE": "Access tentatively granted. Consider secondary verification.",
        "LOW_CONFIDENCE": "Access requires manual verification. Confidence is below recommended threshold.",
        "UNRECOGNIZED": "Access denied. Face not recognized. Alert security personnel."
    }
    return recommendations.get(level, "Unknown security level.")


@app.post("/recognize/batch")
async def recognize_batch(
    files: list[UploadFile] = File(...),
    threshold: float = 0.5
):
    """
    Recognize faces in multiple images at once.
    Returns results for each image.
    """
    if not face_model.is_trained:
        raise HTTPException(
            status_code=400,
            detail="Model is not trained."
        )

    all_results = []

    for file in files:
        try:
            suffix = Path(file.filename).suffix if file.filename else ".jpg"
            with tempfile.NamedTemporaryFile(delete=False, suffix=suffix) as tmp:
                content = await file.read()
                tmp.write(content)
                tmp_path = tmp.name

            result = face_model.recognize(tmp_path, threshold=threshold)
            result["filename"] = file.filename
            all_results.append(result)

        except Exception as e:
            all_results.append({
                "filename": file.filename,
                "error": str(e),
                "faces_detected": 0,
                "results": []
            })
        finally:
            try:
                os.unlink(tmp_path)
            except (OSError, UnboundLocalError):
                pass

    return {
        "total_images": len(files),
        "batch_results": all_results,
        "timestamp": datetime.utcnow().isoformat()
    }


